scale_prices <- function(prices, factor) {
  out <- numeric(length(prices))
  for (i in seq_along(prices)) {
    out[i] <- prices[i] * factor
  }
  out
}

running_total <- function(values, threshold) {
  total <- 0
  for (v in values) {
    if (total + v > threshold) break
    total <- total + v
  }
  total
}
